// ── Header ─────────────────────────────────────────────────────────────────────
export function Header() {
  const [open, setOpen] = React.useState(false)
  const navigate = useNavigate()

  React.useEffect(() => {
    document.body.style.overflow = open ? 'hidden' : ''
    return () => { document.body.style.overflow = '' }
  }, [open])

  return (
    <header className="sticky top-0 z-50 w-full h-20 bg-background backdrop-blur-lg">
      <nav className="mx-auto flex h-full w-full max-w-5xl items-center justify-between px-4">
        <a href="/" className="flex items-center p-2 transition-colors">
          <AppIcon className="w-auto h-12 transition-all duration-300" />
        </a>
        <div className="hidden items-center gap-2 md:flex">
          {NAV_LINKS.map(link => (
            <button
              key={link.label}
              onClick={() => {
                if (link.href.startsWith("#")) {
                  highlightSection(link.href)
                } else {
                  navigate(link.href)
                }
              }}
              className={buttonVariants({ variant: 'ghost' })}
            >
              {link.label}
            </button>
          ))}
          <Button asChild>
            <a href="/home">Launch App</a>
          </Button>
        </div>
        <Button size="icon" variant="outline" onClick={() => setOpen(!open)}
          className="md:hidden" aria-expanded={open} aria-controls="mobile-menu" aria-label="Toggle menu">
          <MenuToggleIcon open={open} className="size-5" duration={300} />
        </Button>
      </nav>
      <MobileMenu open={open} className="flex flex-col justify-between gap-2">
        <div className="grid gap-y-2">
          {NAV_LINKS.map(link => (
            <a key={link.label} className={buttonVariants({ variant: 'ghost', className: 'justify-start' })} href={link.href}>
              {link.label}
            </a>
          ))}
        </div>
        <div className="flex items-center gap-3">
          <Button size="lg" asChild>
            <a href="/home">Launch App</a>
          </Button>
          <Button size="lg" variant="outline" asChild>
            <a href="https://github.com/RonRon-Dev/ENIC-INTERNS-PROJECT" target="_blank" rel="noopener noreferrer">
              <Github className="mr-2 h-4 w-4" />
              GitHub
            </a>
          </Button>
        </div>
      </MobileMenu>
    </header>
  )
}

// ── Helpers ────────────────────────────────────────────────────────────────────

function LogoWithFallback({ item }: { item: typeof TECH_STACK_MARQUEE[number] }) {
  const [failed, setFailed] = useState(false)
  const Icon = item.icon
  if (failed) return <Icon className="w-12 h-12 shrink-0 opacity-60 group-hover:opacity-100 transition-opacity" />
  return (
    <img
      src={item.src}
      alt={item.label}
      className="w-12 h-12 shrink-0 opacity-60 group-hover:opacity-100 transition-opacity"
      onError={() => setFailed(true)}
    />
  )
}

type MobileMenuProps = React.ComponentProps<'div'> & { open: boolean }

function MobileMenu({ open, children, className, ...props }: MobileMenuProps) {
  if (!open || typeof window === 'undefined') return null
  return createPortal(
    <div id="mobile-menu" className={cn(
      'bg-background/95 supports-[backdrop-filter]:bg-background/50 backdrop-blur-lg',
      'fixed top-14 right-0 bottom-0 left-0 z-40 flex flex-col overflow-hidden border-y md:hidden',
    )}>
      <div
        data-slot={open ? 'open' : 'closed'}
        className={cn('data-[slot=open]:animate-in data-[slot=open]:zoom-in-97 ease-out', 'size-full p-4', className)}
        {...props}
      >
        {children}
      </div>
    </div>,
    document.body,
  )
}

